// Защита: если Set-нода недоступна — используем defaults
const config = (() => {
  try { return $('Конфигурация авто-генератора').first().json; } catch (_) {
    return { maxResultLength: 500, maxContextItems: 6, minPromptLength: 5,
             promptAnswerSystem: 'Отвечай JSON: {"answer": "..."}',
             promptPlannerSystem: 'Отвечай JSON: {"prompt": "..."}' };
  }
})();

const toText = (v) => String(v ?? '').trim();
const cleanText = (v, max) => toText(v).replace(/\s+/g, ' ').slice(0, max ?? config.maxResultLength);
// Вырезаем gsd-команды из результата чтобы модель их не копировала
const scrubResult = (v) => toText(v).replace(/\/gsd-[\w-]+(?:\s+[\w"'\-=.]+)*/g, '[команда]').replace(/\s+/g, ' ');

// Данные из диспетчера (is_needs_input, pending_question, completed_task_key, completed_prompt, pending_options_json)
const dispatchInput = (() => {
  try { return $('Триггер: вызов из диспетчера').first().json; } catch (_) { return {}; }
})();

// История задач: может быть пустой при первом запуске
let recentTasks = [];
try { recentTasks = $('Получаем историю задач').all().map(({ json }) => json); } catch (_) {}

const completedKey = dispatchInput.completed_task_key || '';
const context = [
  { prompt: cleanText(dispatchInput.completed_prompt), result: scrubResult(dispatchInput.completed_result || ''), status: 'done' },
  ...recentTasks
    .filter((t) => String(t.task_key ?? '') !== completedKey)
    .map((t) => ({
      prompt: cleanText(t.prompt),
      result: scrubResult(t.result_text || ''),
      status: toText(t.status),
    })),
].slice(0, config.maxContextItems);

// is_needs_input приходит из диспетчера: true = отвечаем на вопрос, false = предлагаем задачу
const needsInput = dispatchInput.is_needs_input === true || dispatchInput.is_needs_input === 'true';

const PROMPTS = {
  true: {
    system: config.promptAnswerSystem || 'Отвечай JSON: {"answer": "..."}',
    user: `Вопрос: ${(() => {
      const q = cleanText(dispatchInput.pending_question);
      if (q) return q;
      try {
        const meta = JSON.parse(dispatchInput.pending_options_json || '{}');
        if (meta.type === 'permission') return meta.message || 'OpenCode запрашивает разрешение на выполнение действия. Ответь: 1 (разрешить один раз), 2 (разрешить всегда), 3 (отклонить).';
        return '(ожидание ответа пользователя)';
      } catch (_) { return '(ожидание ответа пользователя)'; }
    })()}\n\nКонтекст: ${cleanText(dispatchInput.completed_prompt)}`,
  },
  false: {
    system: config.promptPlannerSystem || 'Отвечай JSON: {"prompt": "..."}',
    user: `История задач (самая последняя — ВАЖНЕЕ ВСЕГО, остальные только для контекста):\n\n${context.map((t, i) => (i === 0 ? '>>> ПОСЛЕДНЯЯ <<<\n' : '') + `${i + 1}. ${t.prompt}\n   Результат: ${t.result}`).join('\n\n') || 'Нет истории'}\n\nПредложи следующую задачу.`,
  },
};

const prompt = PROMPTS[String(needsInput)] || PROMPTS.false;
const combinedPrompt = `${prompt.system}

${prompt.user}`;

return {
  json: {
    is_needs_input: needsInput,
    lastTaskKey: dispatchInput.completed_task_key,
    chatId: dispatchInput.chat_id,
    pendingOptionsJson: dispatchInput.pending_options_json || '{}',
    completedPrompt: dispatchInput.completed_prompt || '',
    prompt: combinedPrompt,
  },
};

const toText = (v) => String(v ?? '').trim();

// Защита: AI Agent может не вернуть данных
let rawOutput = {};
try { rawOutput = $('AI Agent').first().json; } catch (_) {}
const content = toText(rawOutput.output ?? rawOutput.text ?? '');

if (!content) {
  return { json: { error: 'AI вернул пустой ответ' } };
}

// Извлекаем JSON из ответа AI с учётом вложенных скобок и строк
function extractJson(text) {
  // 1. Строгий парсинг после удаления markdown-обёртки
  const stripped = text.replace(/```(?:json)?\n?/g, '').replace(/```/g, '').trim();
  try { return JSON.parse(stripped); } catch (_) {}

  // 2. Ищем top-level { ... } — посимвольно, с учётом строк и escape
  const start = text.indexOf('{');
  if (start === -1) return null;
  let depth = 0, inString = false, escape = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (escape) { escape = false; continue; }
    if (ch === '\\') { escape = true; continue; }
    if (ch === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (ch === '{') depth++;
    if (ch === '}') {
      depth--;
      if (depth === 0) {
        try { return JSON.parse(text.slice(start, i + 1)); } catch (_) { return null; }
      }
    }
  }
  return null;
}

const parsed = extractJson(content);
if (!parsed) {
  return { json: { error: 'Не удалось извлечь JSON из ответа AI', content: content.slice(0, 200) } };
}

return { json: { parsed } };

// Защита: fallback-конфиг если Set-нода недоступна
const config = (() => {
  try { return $('Конфигурация авто-генератора').first().json; } catch (_) {
    return { minPromptLength: 5 };
  }
})();

const toText = (v) => String(v ?? '').trim();

const ctxInput = (() => {
  try { return $('Формируем контекст для агента').first().json; } catch (_) { return {}; }
})();

// is_needs_input приходит из диспетчера: true = отвечаем, false = предлагаем задачу
const needsInput = ctxInput.is_needs_input === true;

let data = null;
try { data = $('Извлекаем JSON из ответа').first().json.parsed; } catch (_) {}

if (!data) {
  // fallback: сырой текст из AI (extract-json сохраняет content при ошибке парсинга)
  const extractOut = (() => { try { return $('Извлекаем JSON из ответа').first().json; } catch (_) { return {}; } })();
  const rawFallback = (extractOut.content || '').trim();

  // Санитарная проверка: не оборачиваем мусор
  const looksLikeError = / (error|ошибка|failed|exception|timeout|отказ|не\s+удалось) /i.test(rawFallback);
  const tooShort = rawFallback.length < 3;

  if (rawFallback && !looksLikeError && !tooShort) {
    data = needsInput ? { answer: rawFallback } : { prompt: rawFallback };
  }
}

if (!data) {
  return { json: { error: 'Нет данных для валидации' } };
}

if (needsInput) {
  // Ответ на вопрос — ожидаем поле answer
  const answer = toText(data.answer);
  if (!answer) {
    return { json: { error: 'AI вернул пустой ответ на вопрос' } };
  }
  let opts = {};
  try { opts = JSON.parse(ctxInput.pendingOptionsJson || '{}'); } catch (_) {}
  // Для permission-запросов используем reply, для обычных вопросов — answers
  if (opts.type === 'permission') {
    opts.reply = answer;
  } else {
    opts.answers = [answer];
  }
  return {
    json: {
      is_needs_input: true,
      answer,
      pendingOptionsJson: JSON.stringify(opts),
      taskKey: ctxInput.lastTaskKey || '',
      chatId: ctxInput.chatId || '',
    },
  };
}

// Новая задача — ожидаем поле prompt
const prompt = toText(data.prompt);
if (typeof data.prompt !== 'string' || prompt.length < (config.minPromptLength || 5)) {
  return { json: { error: prompt ? 'AI вернул слишком короткий prompt' : 'AI вернул пустой prompt' } };
}

// Фазовая валидация: AI не должен предлагать ту же команду с увеличенным номером фазы
// Это означает что цикл (plan→execute→review→verify→ship) не был завершён для текущей фазы
const extractPhase = (text) => {
  const m = (text || '').match(/\/gsd-(plan-phase|execute-phase|code-review|verify-work|ship|discuss-phase|add-tests|validate-phase)\s+(\d+)/);
  return m ? { cmd: m[1], num: parseInt(m[2], 10) } : null;
};
const lastGSD = extractPhase(ctxInput.completedPrompt || ctxInput.completed_prompt || '');
const nextGSD = extractPhase(prompt);

if (lastGSD && nextGSD && lastGSD.cmd === nextGSD.cmd && lastGSD.num < nextGSD.num) {
  return { json: { error: `Ошибка авто-генератора: AI предложил /gsd-${nextGSD.cmd} ${nextGSD.num}, но фаза ${lastGSD.num} не завершила цикл. Нельзя переходить к фазе ${nextGSD.num} пока ${lastGSD.num} не прошла plan→execute→review→verify→ship полностью.` } };
}

return {
  json: {
    is_needs_input: false,
    prompt,
    lastTaskKey: ctxInput.lastTaskKey || '',
    chatId: ctxInput.chatId || '',
  },
};

const toText = (v) => String(v ?? '').trim();
const cleanText = (v) => toText(v).replace(/\s+/g, ' ').slice(0, 800);

const config = (() => {
  try { return $('Конфигурация авто-генератора').first().json; } catch (_) {
    return { promptFinalOpinionSystem: 'Ты — агент Итоговое мнение. Исправь команду. Отвечай JSON: {"prompt": "..."}' };
  }
})();

