})();

const ctxInput = (() => {
  try { return $('Формируем контекст для агента').first().json; } catch (_) { return {}; }
})();

const dispatchInput = (() => {
  try { return $('Триггер: вызов из диспетчера').first().json; } catch (_) { return {}; }
})();

const systemPrompt = config.promptFinalOpinionSystem || 'Ты — агент Итоговое мнение. Исправь команду.';

// Собираем полную историю (та же что шла planner-у)
const completedKey = ctxInput.lastTaskKey || '';
let recentTasks = [];
try { recentTasks = $('Получаем историю задач').all().map(({ json }) => json); } catch (_) {}
const scrubResult = (v) => toText(v).replace(/\/gsd-[\w-]+(?:\s+[\w"'\-=.]+)*/g, '[команда]').replace(/\s+/g, ' ');
const context = [
  { prompt: cleanText(dispatchInput.completed_prompt || ctxInput.completedPrompt || ''), result: scrubResult(dispatchInput.completed_result || ''), status: 'done' },
  ...recentTasks
    .filter((t) => String(t.task_key ?? '') !== completedKey)
    .map((t) => ({
      prompt: cleanText(t.prompt),
      result: scrubResult(t.result_text || ''),
      status: toText(t.status),
    })),
].slice(0, 6);

const historyText = context.length > 0
  ? context.map((t, i) => (i === 0 ? '>>> ПОСЛЕДНЯЯ <<<\n' : '') + `${i + 1}. ${t.prompt}\n   Результат: ${t.result}`).join('\n\n')
  : 'Нет истории';

const userPrompt = `История задач:\n\n${historyText}\n\nПредыдущий AI-агент предложил:\n${rawAgentOutput}\n\nОшибка валидации:\n${errorText}\n\nРассуди: кто прав? Выдай СТРОГО JSON: {"prompt": "..."}`;

return {
  json: {
    prompt: systemPrompt + '\n\n' + userPrompt
  }
};

